#!/usr/bin/env node
import assert from 'node:assert'
import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)
const repoRoot = path.resolve(__dirname, '..', '..', '..')

function read(relativePath) {
    return fs.readFileSync(path.join(repoRoot, relativePath), 'utf8')
}

function assertContains(source, snippet, label) {
    assert.ok(source.includes(snippet), `${label} missing: ${snippet}`)
}

function assertNotContains(source, snippet, label) {
    assert.ok(!source.includes(snippet), `${label} still contains: ${snippet}`)
}

function assertMatches(source, pattern, label) {
    assert.ok(pattern.test(source), `${label} missing pattern: ${pattern}`)
}

function assertNotMatches(source, pattern, label) {
    assert.ok(!pattern.test(source), `${label} still matches pattern: ${pattern}`)
}

function assertMatchesAny(source, patterns, label) {
    assert.ok(patterns.some((pattern) => pattern.test(source)), `${label} missing any pattern: ${patterns.map(String).join(' | ')}`)
}

function assertFileExists(relativePath, label) {
    assert.ok(fs.existsSync(path.join(repoRoot, relativePath)), `${label} missing file: ${relativePath}`)
}

function assertInOrder(source, snippets, label) {
    let cursor = -1
    snippets.forEach((snippet) => {
        const index = source.indexOf(snippet, cursor + 1)
        assert.ok(index >= 0, `${label} missing ordered snippet: ${snippet}`)
        cursor = index
    })
}

function testPracticeRoutes() {
    const source = read('apps/writing-vue/src/main.js')
    assertContains(source, "path: '/library'", 'practice library route')
    assertContains(source, "name: 'PracticeLibrary'", 'practice library route')
    assertContains(source, "import('./views/PracticeLibraryPage.vue')", 'practice library lazy view')
    assertContains(source, "path: '/reading/:assetId'", 'practice reading route')
    assertContains(source, "name: 'PracticeReading'", 'practice reading route')
    assertContains(source, "import('./views/PracticeReadingPage.vue')", 'practice reading lazy view')
    assertContains(source, "path: '/reading-suite/:sessionId'", 'practice reading suite route')
    assertContains(source, "name: 'PracticeReadingSuite'", 'practice reading suite route')
    assertContains(source, "import('./views/PracticeReadingSuitePage.vue')", 'practice reading suite lazy view')
    assertContains(source, "path: '/reading/:assetId/review/:sessionId'", 'practice reading replay route')
    assertContains(source, "name: 'PracticeReadingReview'", 'practice reading replay route')
    assertContains(source, "path: '/writing'", 'writing route alias')
    assertContains(source, "component: () => import('./views/ComposePage.vue')", 'writing route component')
    assertContains(source, "redirect: { name: 'PracticeLibrary' }", 'library route compatibility')
    assertContains(source, "window.dispatchEvent(new CustomEvent('app-runtime-ready'))", 'practice shell Electron boot signal')
    assertNotContains(source, 'file:// 兼容', 'business route comment')
}

function testElectronPracticeEntrypoint() {
    const source = read('electron/main.js')
    const preloadSource = read('electron/preload.js')
    assertContains(source, 'function loadPracticeShellPage(route = null)', 'practice shell loader')
    assertContains(source, 'function normalizePracticeShellRoute(rawRoute)', 'practice route normalizer')
    assertContains(source, 'const shellUrl = normalizedRoute', 'practice shell route URL builder')
    assertContains(source, "`${getAppAssetUrl(writingRelativePath)}#${normalizedRoute}`", 'practice shell route hash load')
    assertContains(source, 'mainWindow.loadURL(shellUrl)', 'practice shell app protocol load')
    assertContains(source, 'function loadBootRecoveryPage()', 'boot recovery page loader')
    assertContains(source, "title: 'Practice Shell 未构建'", 'practice shell missing build fallback copy')
    assertContains(source, '启动恢复页', 'practice shell missing build recovery copy')
    assertNotContains(source, "ipcMain.on('navigate-to-legacy'", 'legacy fallback IPC removed')
    assertNotContains(source, "ipcMain.on('navigate-to-writing'", 'writing IPC compatibility removed')
    assertNotContains(source, 'loadLegacyPage', 'legacy product page loader removed')
    assertNotContains(source, 'loadWritingPage', 'standalone writing page loader removed')
    assertContains(source, "ipcMain.handle('navigate-to-practice-route'", 'practice route IPC')
    assertContains(source, 'isValidNavigationSource(event)', 'practice route IPC source guard')
    assertContains(source, "error: 'invalid_practice_route'", 'practice route invalid guard')
    assertContains(source, "/^\\/reading\\/[A-Za-z0-9._-]+", 'practice reading route allowlist')
    assertContains(source, "/^\\/reading-suite\\/[A-Za-z0-9._-]+", 'practice reading suite route allowlist')
    assertContains(preloadSource, 'openPracticeRoute', 'preload practice route bridge')
    assertContains(preloadSource, 'openPracticeReading', 'preload practice reading bridge')
    assertContains(preloadSource, 'PRACTICE_ASSET_ID_PATTERN', 'preload practice asset id guard')
    assertContains(preloadSource, "invoke('navigate-to-practice-route'", 'preload route IPC invoke')
    assertNotContains(preloadSource, 'openLegacy', 'preload legacy navigation bridge removed')
    assertNotContains(preloadSource, 'openWriting', 'preload standalone writing bridge removed')
    assertMatches(source, /loadPracticeShellPage\(\);\s*return mainWindow;/, 'default Electron entry loads Vue Practice Shell')
}

