function testLegacyBridgeConvergenceContract() {
    const legacyBridgePath = 'apps/writing-vue/src/modules/legacy/legacyBridge.ts'
    const legacyScriptLoaderPath = 'apps/writing-vue/src/modules/legacy/legacyScriptLoader.ts'
    const legacyBridgeSource = read(legacyBridgePath)
    const legacyScriptLoaderSource = read(legacyScriptLoaderPath)
    const readingTimerSource = read('apps/writing-vue/src/modules/practice-reading/useReadingTimer.ts')
    const librarySource = read('apps/writing-vue/src/views/PracticeLibraryPage.vue')
    const settingsSource = read('apps/writing-vue/src/views/SettingsPage.vue')
    const shuiSource = read('apps/writing-vue/src/components/ShuiBackground.vue')
    const legacySurfaceSource = [
        legacyBridgeSource,
        legacyScriptLoaderSource,
        librarySource,
        settingsSource,
        shuiSource
    ].join('\n')

    assertFileExists(legacyBridgePath, 'legacy bridge module')
    assertFileExists(legacyScriptLoaderPath, 'legacy script loader module')
    assertContains(legacyBridgeSource, '__IELTS_PRACTICE_TIMER__', 'legacy bridge preserves timer bridge key')
    assertContains(legacyBridgeSource, 'practiceTimerStateChange', 'legacy bridge preserves timer event name')
    assertMatchesAny(legacyBridgeSource, [/installTimerBridge/, /createPracticeTimerBridge/, /syncPracticeTimerBridge/], 'legacy bridge exposes timer bridge API')
    assertMatchesAny(legacySurfaceSource, [/shui-bg-theme-change/, /switchBgTheme/], 'legacy bridge surface preserves Shui background theme bridge')
    assertMatchesAny(legacySurfaceSource, [/OnboardingTour/, /AppUpdateManager/], 'legacy bridge surface preserves onboarding/update manager bridge contract')
    assertMatchesAny(legacyScriptLoaderSource, [/document\.createElement\('script'\)/, /document\.createElement\("script"\)/], 'legacy script loader owns legacy script tag creation')
    assertMatchesAny(legacyScriptLoaderSource, [/document\.createElement\('link'\)/, /document\.createElement\("link"\)/], 'legacy script loader owns legacy style tag creation')
    assertMatchesAny(legacyScriptLoaderSource, [/new Map\(\)/, /const .*Promises = new Map\(\)/], 'legacy script loader owns loader dedupe map')

    assertNotContains(readingTimerSource, "window[PRACTICE_TIMER_BRIDGE_KEY]", 'reading timer composable must not write timer bridge directly')
    assertNotContains(readingTimerSource, 'delete window[PRACTICE_TIMER_BRIDGE_KEY]', 'reading timer composable must not delete timer bridge directly')
    assertNotContains(readingTimerSource, 'window.dispatchEvent(new CustomEvent(PRACTICE_TIMER_EVENT', 'reading timer composable must not dispatch timer event directly')
    assertMatchesAny(readingTimerSource, [/from ['"]@\/modules\/legacy\/legacyBridge['"]/, /from ['"]\.\.\/legacy\/legacyBridge['"]/], 'reading timer composable imports legacy bridge')
    assertMatchesAny(readingTimerSource, [/installTimerBridge/, /removeTimerBridge/, /emitPracticeTimerStateChange/, /legacyBridge/], 'reading timer composable delegates bridge work to legacy bridge')

    assertNotMatches(librarySource, /const\s+legacyStylePromises\s*=\s*new Map\(\)/, 'practice library must not own legacy style promise map')
    assertNotMatches(librarySource, /const\s+legacyScriptPromises\s*=\s*new Map\(\)/, 'practice library must not own legacy script promise map')
    assertNotMatches(librarySource, /function\s+loadLegacyStyle\s*\(/, 'practice library must not own legacy style loader')
    assertNotMatches(librarySource, /function\s+loadLegacyScript\s*\(/, 'practice library must not own legacy script loader')
    assertNotMatches(librarySource, /document\.createElement\((['"])link\1\)/, 'practice library must not create legacy link elements directly')
    assertNotMatches(librarySource, /document\.createElement\((['"])script\1\)/, 'practice library must not create legacy script elements directly')
    assertMatchesAny(librarySource, [/from ['"]@\/modules\/legacy\/legacyBridge['"]/, /from ['"]@\/modules\/legacy\/legacyScriptLoader['"]/], 'practice library imports legacy bridge/loader module')
    assertContains(legacySurfaceSource, 'js/utils/vocabDataIO.js', 'legacy bridge surface preserves more tools script list contract')
    assertInOrder(legacySurfaceSource, [
        "'js/utils/vocabDataIO.js'",
        "'js/core/vocabScheduler.js'",
        "'js/core/vocabStore.js'",
        "'js/app/vocabListSwitcher.js'",
        "'js/components/vocabDashboardCards.js'",
        "'js/components/vocabSessionView.js'",
        "'js/services/achievementManager.js'",
        "'js/presentation/moreView.js'"
    ], 'practice library preserves more tools script order')

    assertNotMatches(settingsSource, /const\s+legacyStylePromises\s*=\s*new Map\(\)/, 'writing settings must not own legacy style promise map')
    assertNotMatches(settingsSource, /const\s+legacyScriptPromises\s*=\s*new Map\(\)/, 'writing settings must not own legacy script promise map')
    assertNotMatches(settingsSource, /function\s+loadLegacyStyle\s*\(/, 'writing settings must not own legacy style loader')
    assertNotMatches(settingsSource, /function\s+loadLegacyScript\s*\(/, 'writing settings must not own legacy script loader')
    assertNotMatches(settingsSource, /document\.createElement\((['"])link\1\)/, 'writing settings must not create legacy link elements directly')
    assertNotMatches(settingsSource, /document\.createElement\((['"])script\1\)/, 'writing settings must not create legacy script elements directly')
    assertMatchesAny(settingsSource, [/from ['"]@\/modules\/legacy\/legacyBridge['"]/, /from ['"]@\/modules\/legacy\/legacyScriptLoader['"]/], 'writing settings imports legacy bridge/loader module')
    assertContains(legacySurfaceSource, 'css/onboarding.css', 'legacy bridge surface preserves onboarding stylesheet contract')
    assertContains(legacySurfaceSource, 'js/components/onboardingTour.js', 'legacy bridge surface preserves onboarding runtime contract')
    assertContains(legacySurfaceSource, 'js/integration/updateManager.js', 'legacy bridge surface preserves update manager runtime contract')
    assertContains(legacyBridgeSource, 'legacyWindow.OnboardingTour.start(true)', 'legacy bridge surface preserves onboarding start contract')
    assertContains(legacySurfaceSource, "handleAction('open-modal')", 'legacy bridge surface preserves update manager open-modal contract')

    assertNotMatches(shuiSource, /function\s+loadLegacyScript\s*\(/, 'Shui background must not own legacy script loader')
    assertNotMatches(shuiSource, /document\.createElement\((['"])script\1\)/, 'Shui background must not create legacy script elements directly')
    assertMatchesAny(shuiSource, [/from ['"]@\/modules\/legacy\/legacyBridge['"]/, /from ['"]@\/modules\/legacy\/legacyScriptLoader['"]/], 'Shui background imports legacy bridge/loader module')
    assertContains(shuiSource, "const THREE_VENDOR_SCRIPT = 'assets/vendor/three.min.js'", 'Shui background preserves vendor script path')
    assertContains(shuiSource, "const THREE_BACKGROUND_SCRIPT = 'js/presentation/threeBackground.js'", 'Shui background preserves background script path')
}

